module multiplexer_4to1 (
    input [3:0] obf_in,
    input [1:0] sel,
    output reg out);
always @(*) begin
    case (sel)
        2'b00: out = obf_in[0];
        2'b01: out = obf_in[1];
        2'b10: out = obf_in[2];
        2'b11: out = obf_in[3];
        default: out = 1'b0;
    endcase
end
endmodule
